/* global document */
import React from 'react';
import PropTypes from 'prop-types';

/** @typedef {import('../..').CloseListenerProps} CloseListenerProps */

/** @extends React.Component<CloseListenerProps> */
class CloseListener extends React.Component {
  /** @param {CloseListenerProps} props */
  constructor(props) {
    super(props);
    this.handleRef = this.handleRef.bind(this);
    this.handleDocumentClick = this.handleDocumentClick.bind(this);
    this.pressEscToClose = this.pressEscToClose.bind(this);
  }

  componentDidMount() {
    document.addEventListener('click', this.handleDocumentClick);
    document.addEventListener('keydown', this.pressEscToClose, false);
  }

  componentWillUnmount() {
    document.removeEventListener('click', this.handleDocumentClick);
    document.removeEventListener('keydown', this.pressEscToClose, false);
  }

  /** @param {KeyboardEvent} event */
  pressEscToClose(event) {
    const { handleEsc = true, onCloseOutside } = this.props;

    if (handleEsc) {
      if (event.code === 'Escape') { // esc key
        onCloseOutside(event);
      }
    }
  }

  /** @param {MouseEvent} event */
  handleDocumentClick(event) {
    const { handleClick = true, onCloseOutside } = this.props;

    if (handleClick) {
      if (this.element && !this.element.contains(/** @type {Node} */ (event.target))) {
        onCloseOutside(event);
      }
    }
  }

  /** @param {HTMLElement} el */
  handleRef(el) {
    const { children } = this.props;

    this.element = el;
    // @ts-expect-error ref prop doesn't exist on ReactElement
    if (children.ref && typeof children.ref === 'function') {
      // @ts-expect-error ref prop doesn't exist on ReactElement
      children.ref(el);
    }
  }

  render() {
    const { children } = this.props;

    return React.cloneElement(/** @type {React.ReactElement} */ (children), {
      ref: this.handleRef,
    });
  }
}

CloseListener.propTypes = {
  children: PropTypes.element.isRequired,
  onCloseOutside: PropTypes.func.isRequired,
  handleClick: PropTypes.bool,
  handleEsc: PropTypes.bool,
};

export default CloseListener;

